package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import java.util.Arrays;
import java.util.Random;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotEquals;

class ClonePair6274DifferenceFindingTest {

    private final ClonePair6274 subject = new ClonePair6274();

    /**
     * Generated by Codex (GPT-5.4).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnGeneratedInput() {
        Random method1Random = new Random(0L);
        Random method2Random = new Random(0L);

        boolean[][] method1Result = subject.method1(3, 1.0, method1Random);
        boolean[][] method2Result = subject.method2(3, 1.0, method2Random);

        assertEquals(
            "[[false, true, true], [true, false, true], [true, true, false]]",
            Arrays.deepToString(method1Result)
        );
        assertEquals(
            "[[false, true, true], [true, false, false], [true, false, false]]",
            Arrays.deepToString(method2Result)
        );
        assertNotEquals(Arrays.deepToString(method1Result), Arrays.deepToString(method2Result));

        assertEquals(0.5504370051176339, method1Random.nextDouble());
        assertEquals(0.6374174253501083, method2Random.nextDouble());
    }
}
